549: // cfgMeal is the data involved in the process of digesting the API
550: // objects that configure API Priority and Fairness.  All the config
551: // objects are digested together, because this is the simplest way to
552: // cope with the various dependencies between objects.  The process of
553: // digestion is done in four passes over config objects --- three
554: // passes over PriorityLevelConfigurations and one pass over the
555: // FlowSchemas --- with the work dvided among the passes according to
556: // those dependencies.
557: type cfgMeal struct {
558: 	cfgCtlr *configController
559: 
560: 	newPLStates map[string]*priorityLevelState
561: 
562: 	// The sum of the concurrency shares of the priority levels in the
563: 	// new configuration
564: 	shareSum float64
565: 
566: 	// These keep track of which mandatory priority level config
567: 	// objects have been digested
568: 	haveExemptPL, haveCatchAllPL bool
569: 
570: 	// Buffered FlowSchema status updates to do.  Do them when the
571: 	// lock is not held, to avoid a deadlock due to such a request
572: 	// provoking a call into this controller while the lock held
573: 	// waiting on that request to complete.
574: 	fsStatusUpdates []fsStatusUpdate
575: 
576: 	maxWaitingRequests, maxExecutingRequests int
