651: // shouldDelayUpdate checks to see if a flowschema has been updated too often and returns true if a delay is needed.
652: // Only invoke this in the one and only worker goroutine
653: func (cfgCtlr *configController) shouldDelayUpdate(flowSchemaName string) bool {
654: 	numUpdatesInPastMinute := 0
655: 	oneMinuteAgo := cfgCtlr.clock.Now().Add(-1 * time.Minute)
656: 	for idx, update := range cfgCtlr.mostRecentUpdates {
657: 		if oneMinuteAgo.After(update.timeUpdated) {
658: 			// this and the remaining items are no longer relevant
659: 			cfgCtlr.mostRecentUpdates = cfgCtlr.mostRecentUpdates[:idx]
660: 			return false
661: 		}
662: 		if update.updatedItems.Has(flowSchemaName) {
663: 			numUpdatesInPastMinute++
664: 			if numUpdatesInPastMinute > 5 {
665: 				return true
666: 			}
667: 		}
668: 	}
669: 	return false
670: }
