1017: // startRequest classifies and, if appropriate, enqueues the request.
1018: // Returns a nil Request if and only if the request is to be rejected.
1019: // The returned bool indicates whether the request is exempt from
1020: // limitation.  The startWaitingTime is when the request started
1021: // waiting in its queue, or `Time{}` if this did not happen.
1022: func (cfgCtlr *configController) startRequest(ctx context.Context, rd RequestDigest,
1023: 	noteFn func(fs *flowcontrol.FlowSchema, pl *flowcontrol.PriorityLevelConfiguration, flowDistinguisher string),
1024: 	workEstimator func() fcrequest.WorkEstimate,
1025: 	queueNoteFn fq.QueueNoteFn) (fs *flowcontrol.FlowSchema, pl *flowcontrol.PriorityLevelConfiguration, isExempt bool, req fq.Request, startWaitingTime time.Time) {
1026: 	klog.V(7).Infof("startRequest(%#+v)", rd)
1027: 	cfgCtlr.lock.RLock()
1028: 	defer cfgCtlr.lock.RUnlock()
1029: 	var selectedFlowSchema, catchAllFlowSchema *flowcontrol.FlowSchema
1030: 	for _, fs := range cfgCtlr.flowSchemas {
1031: 		if matchesFlowSchema(rd, fs) {
1032: 			selectedFlowSchema = fs
1033: 			break
1034: 		}
1035: 		if fs.Name == flowcontrol.FlowSchemaNameCatchAll {
1036: 			catchAllFlowSchema = fs
1037: 		}
1038: 	}
1039: 	if selectedFlowSchema == nil {
1040: 		// This should never happen. If the requestDigest's User is a part of
1041: 		// system:authenticated or system:unauthenticated, the catch-all flow
1042: 		// schema should match it. However, if that invariant somehow fails,
1043: 		// fallback to the catch-all flow schema anyway.
1044: 		if catchAllFlowSchema == nil {
1045: 			// This should absolutely never, ever happen! APF guarantees two
1046: 			// undeletable flow schemas at all times: an exempt flow schema and a
1047: 			// catch-all flow schema.
1048: 			panic(fmt.Sprintf("no fallback catch-all flow schema found for request %#+v and user %#+v", rd.RequestInfo, rd.User))
1049: 		}
1050: 		selectedFlowSchema = catchAllFlowSchema
1051: 		klog.Warningf("no match found for request %#+v and user %#+v; selecting catchAll=%s as fallback flow schema", rd.RequestInfo, rd.User, fcfmt.Fmt(selectedFlowSchema))
1052: 	}
1053: 	plName := selectedFlowSchema.Spec.PriorityLevelConfiguration.Name
1054: 	plState := cfgCtlr.priorityLevelStates[plName]
1055: 	var numQueues int32
1056: 	var hashValue uint64
1057: 	var flowDistinguisher string
1058: 	if plState.pl.Spec.Type != flowcontrol.PriorityLevelEnablementExempt {
1059: 		if plState.pl.Spec.Limited.LimitResponse.Type == flowcontrol.LimitResponseTypeQueue {
1060: 			numQueues = plState.pl.Spec.Limited.LimitResponse.Queuing.Queues
1061: 		}
1062: 		if numQueues > 1 {
1063: 			flowDistinguisher = computeFlowDistinguisher(rd, selectedFlowSchema.Spec.DistinguisherMethod)
1064: 			hashValue = hashFlowID(selectedFlowSchema.Name, flowDistinguisher)
1065: 		}
1066: 	}
1067: 
1068: 	noteFn(selectedFlowSchema, plState.pl, flowDistinguisher)
1069: 	workEstimate := workEstimator()
1070: 
1071: 	if plState.pl.Spec.Type != flowcontrol.PriorityLevelEnablementExempt {
1072: 		startWaitingTime = cfgCtlr.clock.Now()
1073: 	}
1074: 	klog.V(7).Infof("startRequest(%#+v) => fsName=%q, distMethod=%#+v, plName=%q, numQueues=%d", rd, selectedFlowSchema.Name, selectedFlowSchema.Spec.DistinguisherMethod, plName, numQueues)
1075: 	req, idle := plState.queues.StartRequest(ctx, &workEstimate, hashValue, flowDistinguisher, selectedFlowSchema.Name, rd.RequestInfo, rd.User, queueNoteFn)
1076: 	if idle {
1077: 		cfgCtlr.maybeReapReadLocked(plName, plState)
1078: 	}
1079: 	return selectedFlowSchema, plState.pl, plState.pl.Spec.Type == flowcontrol.PriorityLevelEnablementExempt, req, startWaitingTime
1080: }
