1082: // maybeReap will remove the last internal traces of the named
1083: // priority level if it has no more use.  Call this after getting a
1084: // clue that the given priority level is undesired and idle.
1085: func (cfgCtlr *configController) maybeReap(plName string) {
1086: 	cfgCtlr.lock.RLock()
1087: 	defer cfgCtlr.lock.RUnlock()
